package com.example.battleship.controller;

import com.example.battleship.game.GameManager;
import com.example.battleship.game.GameSession;
import com.example.battleship.view.SceneManager;
import javafx.fxml.FXML;
import javafx.scene.control.Button;
import javafx.scene.control.Label;

@SuppressWarnings("unused")
public class EndController {

    @FXML private Label lblTitle;
    @FXML private Label lblPlayerNickname;
    @FXML private Label lblEnemyShipsSunk;
    @FXML private Label lblPlayerMissedShots;
    @FXML private Label lblPlayerShipsSunk;
    @FXML private Label lblEnemyMissedShots;
    @FXML private Button btnMainMenu;

    @FXML
    public void initialize() {
        GameManager gameManager = GameSession.getInstance().getCurrentGameManager();
        if (gameManager == null) {
            lblTitle.setText("⚓ PARTIDA FINALIZADA");
            lblPlayerNickname.setText(" JUGADOR: N/D");
            lblEnemyShipsSunk.setText("0 / 10");
            lblPlayerMissedShots.setText("0");
            lblPlayerShipsSunk.setText("0 / 10");
            lblEnemyMissedShots.setText("0");
            return;
        }

        boolean humanWon = gameManager.getMachine().getBoard().isFleetDefeated();
        lblTitle.setText(humanWon ? " VICTORIA " : " DERROTA ");
        lblPlayerNickname.setText(" JUGADOR: " + gameManager.getNickname());
        lblEnemyShipsSunk.setText(gameManager.getMachine().getBoard().getFleet().getSunkShipsCount() + " / 10");
        lblPlayerMissedShots.setText(String.valueOf(countShots(gameManager.getMachine().getBoard().getBoard().values(), com.example.battleship.model.enums.CellState.WATER)));
        lblPlayerShipsSunk.setText(gameManager.getHuman().getBoard().getFleet().getSunkShipsCount() + " / 10");
        lblEnemyMissedShots.setText(String.valueOf(countShots(gameManager.getHuman().getBoard().getBoard().values(), com.example.battleship.model.enums.CellState.WATER)));
    }

    private long countShots(java.util.Collection<com.example.battleship.model.Cell> cells, com.example.battleship.model.enums.CellState state) {
        return cells.stream().filter(cell -> cell.getCellState() == state).count();
    }

    @FXML
    private void onRestartButtonClick() {
        SceneManager.getInstance().changeScene("menu-view.fxml");
    }
}

package com.example.battleship.controller;

import com.example.battleship.view.SceneManager;
import javafx.fxml.FXML;
import javafx.scene.control.Button; // <-- ESTA IMPORTACIÓN TE FALTABA
import javafx.scene.control.Label;
import javafx.scene.layout.GridPane;
import javafx.scene.layout.Pane;
import javafx.scene.input.MouseEvent;

public class GameController {

    @FXML private GridPane playerGrid;
    @FXML private GridPane enemyGrid;
    @FXML private Label turnLabel;
    @FXML private Label actionStatusLabel;
    @FXML private Button viewEnemyShipsButton; // Vinculado a tu FXML

    private boolean showingEnemyShips = false;

    @FXML
    public void initialize() {
        buildGrid(playerGrid, false);
        buildGrid(enemyGrid, true);

        turnLabel.setText("Tu Turno: Comanda el ataque");
        actionStatusLabel.setText("Selecciona una coordenada en el radar enemigo.");
    }

    private void buildGrid(GridPane grid, boolean isInteractive) {
        grid.getChildren().clear();
        for (int row = 0; row < 10; row++) {
            for (int col = 0; col < 10; col++) {
                Pane cell = new Pane();
                cell.setPrefSize(32, 32);

                cell.setStyle("-fx-border-color: rgba(0, 255, 255, 0.2); -fx-background-color: rgba(10, 20, 40, 0.6);");

                if (isInteractive) {
                    cell.setId("cell_" + row + "_" + col);

                    cell.setOnMouseEntered(e -> cell.setStyle("-fx-border-color: #00ffff; -fx-background-color: rgba(0, 255, 255, 0.25);"));
                    cell.setOnMouseExited(e -> cell.setStyle("-fx-border-color: rgba(0, 255, 255, 0.2); -fx-background-color: rgba(10, 20, 40, 0.6);"));

                    cell.setOnMouseClicked(this::handleAttackEvent);
                }
                grid.add(cell, col, row);
            }
        }
    }

    private void handleAttackEvent(MouseEvent event) {
        Pane targetCell = (Pane) event.getSource();
        String[] coords = targetCell.getId().split("_");
        int row = Integer.parseInt(coords[1]);
        int col = Integer.parseInt(coords[2]);

        if ((row + col) % 3 == 0) {
            targetCell.setStyle("-fx-background-color: #ff3333; -fx-border-color: #ff0000;");
            actionStatusLabel.setText("¡Impacto confirmado en: [" + row + ", " + col + "]!");
        } else {
            targetCell.setStyle("-fx-background-color: rgba(255, 255, 255, 0.4); -fx-border-color: #cccccc;");
            actionStatusLabel.setText("Disparo fallido en agua en: [" + row + ", " + col + "].");
        }

        targetCell.setOnMouseClicked(null);
        targetCell.setOnMouseEntered(null);
        targetCell.setOnMouseExited(null);
    }

    @FXML
    private void onViewEnemyShipsButtonClick() {
        showingEnemyShips = !showingEnemyShips;

        if (showingEnemyShips) {
            viewEnemyShipsButton.setText(" Ocultar Barcos Enemigos");
            actionStatusLabel.setText("¡Satélite activado! Viendo la ubicación de la flota enemiga.");

            for (javafx.scene.Node node : enemyGrid.getChildren()) {
                if (node instanceof Pane) {
                    Pane cell = (Pane) node;
                    String id = cell.getId();
                    if (id != null) {
                        String[] coords = id.split("_");
                        int row = Integer.parseInt(coords[1]);
                        int col = Integer.parseInt(coords[2]);

                        if ((row + col) % 3 == 0) {
                            cell.setStyle("-fx-background-color: rgba(155, 0, 255, 0.7); -fx-border-color: #9900ff;");
                        }
                    }
                }
            }
        } else {
            viewEnemyShipsButton.setText(" Ver Barcos Enemigos");
            actionStatusLabel.setText("Modo radar normal restaurado.");

            for (javafx.scene.Node node : enemyGrid.getChildren()) {
                if (node instanceof Pane) {
                    Pane cell = (Pane) node;
                    if (cell.getOnMouseClicked() != null) {
                        cell.setStyle("-fx-border-color: rgba(255, 51, 51, 0.2); -fx-background-color: rgba(10, 20, 40, 0.6);");
                    }
                }
            }
        }
    }

    @FXML
    private void onSurrenderButtonClick() {
        SceneManager.getInstance().changeScene("end-view.fxml");
    }
}

package com.example.battleship.controller;

import com.example.battleship.game.GameManager;
import com.example.battleship.game.GameSession;
import com.example.battleship.model.Coordinate;
import com.example.battleship.model.enums.CellState;
import com.example.battleship.model.ships.Ship;
import com.example.battleship.view.ModelToViewMapper;
import com.example.battleship.view.SceneManager;
import com.example.battleship.view.ShipView;
import javafx.application.Platform;
import javafx.fxml.FXML;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.ToggleButton;
import javafx.scene.input.MouseEvent;
import javafx.scene.layout.GridPane;
import javafx.scene.layout.Pane;

import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;
import java.util.logging.Level;
import java.util.logging.Logger;

public class GameController {

    private static final Logger LOGGER = Logger.getLogger(GameController.class.getName());

    @FXML private GridPane gridPlayerBoard;
    @FXML private GridPane gridEnemyBoard;
    @FXML private Label lblPlayerName;
    @FXML private Label lblPlayerShipsLeft;
    @FXML private Label lblTurnStatus;
    @FXML private Label lblEnemyShipsLeft;
    @FXML private Label actionStatusLabel;
    @FXML private ToggleButton btnToggleEnemyBoard;
    @FXML private Button btnSaveAndExit;

    private boolean showingEnemyShips = false;
    private GameManager gameManager;
    private final ScheduledExecutorService machineExecutor = Executors.newSingleThreadScheduledExecutor();
    private volatile boolean machineTurnScheduled;

    @FXML
    public void initialize() {
        gameManager = GameSession.getInstance().requireGameManager();
        if (!gameManager.getHuman().isFleetComplete()) {
            SceneManager.getInstance().changeScene("shipplacement-view.fxml");
            return;
        }

        buildGrid(gridPlayerBoard, false);
        buildGrid(gridEnemyBoard, true);

        ModelToViewMapper.bindBoardToGrid(gameManager.getHuman().getBoard(), gridPlayerBoard, true);
        ModelToViewMapper.bindBoardToGrid(gameManager.getMachine().getBoard(), gridEnemyBoard, false);

        lblPlayerName.setText("Comandante: " + gameManager.getNickname());
        refreshCounters();
        lblTurnStatus.setText(gameManager.isHumanTurn() ? " TURNO DEL JUGADOR" : " TURNO DE LA IA");
        actionStatusLabel.setText("Selecciona una coordenada en el radar enemigo.");
    }

    private void buildGrid(GridPane grid, boolean isInteractive) {
        grid.getChildren().clear();
        for (int row = 0; row < 10; row++) {
            for (int col = 0; col < 10; col++) {
                Pane cell = new Pane();
                cell.setPrefSize(32, 32);
                cell.setId("cell_" + row + "_" + col);
                cell.setStyle("-fx-border-color: rgba(0, 255, 255, 0.2); -fx-background-color: rgba(10, 20, 40, 0.6);");
                if (isInteractive) {
                    cell.setOnMouseEntered(e -> cell.setStyle("-fx-border-color: #00ffff; -fx-background-color: rgba(0, 255, 255, 0.25);") );
                    cell.setOnMouseExited(e -> cell.setStyle("-fx-border-color: rgba(0, 255, 255, 0.2); -fx-background-color: rgba(10, 20, 40, 0.6);") );
                    cell.setOnMouseClicked(this::handleAttackEvent);
                }
                grid.add(cell, col, row);
            }
        }
    }

    private void handleAttackEvent(MouseEvent event) {
        Pane targetCell = (Pane) event.getSource();
        String[] coords = targetCell.getId().split("_");
        int row = Integer.parseInt(coords[1]);
        int col = Integer.parseInt(coords[2]);

        try {
            Coordinate c = new Coordinate(row, col);
            CellState result = gameManager.humanShoot(c);
            targetCell.setOnMouseClicked(null);
            targetCell.setOnMouseEntered(null);
            targetCell.setOnMouseExited(null);

            actionStatusLabel.setText("Resultado: " + result);
            refreshCounters();
            persistGame();

            if (gameManager.getMachine().getBoard().isFleetDefeated()) {
                machineExecutor.shutdownNow();
                lblTurnStatus.setText(" VICTORIA");
                actionStatusLabel.setText("¡Felicidades! Has hundido toda la flota enemiga.");
                return;
            }

            if (result == CellState.WATER) {
                scheduleMachineTurn();
            } else {
                lblTurnStatus.setText(" TURNO DEL JUGADOR");
                actionStatusLabel.setText("Has acertado, sigue disparando.");
            }
        } catch (Exception e) {
            LOGGER.log(Level.WARNING, "Error al procesar disparo", e);
            actionStatusLabel.setText("Coordenada inválida o error al disparar: " + e.getMessage());
        }
    }

    @FXML
    private void onViewEnemyShipsButtonClick() {
        showingEnemyShips = !showingEnemyShips;
        gridEnemyBoard.getChildren().removeIf(n -> n instanceof ShipView);

        if (showingEnemyShips) {
            btnToggleEnemyBoard.setText(" Ocultar Barcos Enemigos");
            actionStatusLabel.setText("¡Satélite activado! Viendo la ubicación de la flota enemiga.");

            for (Ship ship : gameManager.getMachine().getBoard().getFleet().getShips()) {
                ShipView view = ShipView.placeOnGrid(gridEnemyBoard, ship);
                view.setMouseTransparent(true);
            }
        } else {
            btnToggleEnemyBoard.setText(" Ver Barcos Enemigos");
            actionStatusLabel.setText("Modo radar normal restaurado.");
            buildGrid(gridEnemyBoard, true);
            ModelToViewMapper.bindBoardToGrid(gameManager.getMachine().getBoard(), gridEnemyBoard, false);
        }
    }

    @FXML
    private void onSurrenderButtonClick() {
        persistGame();
        machineExecutor.shutdownNow();
        SceneManager.getInstance().changeScene("menu-view.fxml");
    }

    private void persistGame() {
        GameSession.getInstance().saveCurrentGame();
    }

    private void refreshCounters() {
        int humanRemaining = gameManager.getHuman().getBoard().getFleet().getRemainingShipsCount();
        int machineRemaining = gameManager.getMachine().getBoard().getFleet().getRemainingShipsCount();
        lblPlayerShipsLeft.setText("Flota Aliada: Restantes " + humanRemaining + "/10 | Hundidos " + gameManager.getHuman().getBoard().getFleet().getSunkShipsCount() + "/10");
        lblEnemyShipsLeft.setText("Flota Enemiga: Restantes " + machineRemaining + "/10 | Hundidos " + gameManager.getMachine().getBoard().getFleet().getSunkShipsCount() + "/10");
    }

    private void scheduleMachineTurn() {
        if (machineTurnScheduled) {
            return;
        }
        machineTurnScheduled = true;
        lblTurnStatus.setText(" TURNO DE LA IA");
        machineExecutor.schedule(this::executeMachineTurnStep, 600, TimeUnit.MILLISECONDS);
    }

    private void executeMachineTurnStep() {
        try {
            CellState result = gameManager.machineShoot();
            persistGame();
            Platform.runLater(this::refreshCounters);

            if (gameManager.getHuman().getBoard().isFleetDefeated()) {
                machineExecutor.shutdownNow();
                Platform.runLater(() -> {
                    actionStatusLabel.setText("Has perdido. La máquina hundió toda tu flota.");
                    lblTurnStatus.setText("☠ DERROTA");
                });
                machineTurnScheduled = false;
                return;
            }

            if (result == CellState.WATER) {
                Platform.runLater(() -> {
                    lblTurnStatus.setText(" TURNO DEL JUGADOR");
                    actionStatusLabel.setText("La IA falló. Vuelve a disparar.");
                });
                machineTurnScheduled = false;
            } else {
                machineExecutor.schedule(this::executeMachineTurnStep, 600, TimeUnit.MILLISECONDS);
            }
        } catch (Exception ex) {
            LOGGER.log(Level.WARNING, "Error en el turno de la IA", ex);
            machineTurnScheduled = false;
        }
    }
}

package com.example.battleship.controller;

import com.example.battleship.view.SceneManager;
import javafx.fxml.FXML;
import javafx.scene.control.Button;
import javafx.scene.control.TextField;

public class MenuController {

    @FXML private TextField nicknameField;
    @FXML private Button startButton;

    @FXML
    public void initialize() {
        startButton.disableProperty().bind(nicknameField.textProperty().isEmpty());
    }


    @FXML
    private void onLoadGameButtonClick() {
        System.out.println("Cargando partida guardada...");
        SceneManager.getInstance().changeScene("game-view.fxml");
    }

    @FXML
    private void onStartButtonClick() {
        String playerNickname = nicknameField.getText().trim();
        System.out.println("Jugador registrado: " + playerNickname);



        SceneManager.getInstance().changeScene("game-view.fxml");
    }

    @FXML
    private void onExitButtonClick() {
        System.exit(0);
    }
}

package com.example.battleship.controller;

import com.example.battleship.game.GameSession;
import com.example.battleship.view.SceneManager;
import javafx.fxml.FXML;
import javafx.scene.control.Button;
import javafx.scene.control.Alert;
import javafx.scene.control.TextField;

public class MenuController {

    // fx:id names must match those defined in FXML
    @FXML private TextField txtNickname;
    @FXML private Button btnNewGame;
    @FXML private Button btnContinue;
    @FXML private Button btnExit;

    @FXML
    public void initialize() {
        // disable "New Game" until nickname is provided
        btnNewGame.disableProperty().bind(txtNickname.textProperty().isEmpty());
        btnContinue.setDisable(!GameSession.getInstance().hasSavedGame());
    }

    @FXML
    private void handleNewGame() {
        String playerNickname = txtNickname.getText().trim();
        GameSession.getInstance().startNewGame(playerNickname);
        SceneManager.getInstance().changeScene("shipplacement-view.fxml");
    }

    @FXML
    private void handleContinue() {
        if (GameSession.getInstance().loadLatestSave()) {
            boolean placementComplete = GameSession.getInstance().getCurrentGameManager() != null
                    && GameSession.getInstance().getCurrentGameManager().getHuman().isFleetComplete();
            SceneManager.getInstance().changeScene(placementComplete ? "game-view.fxml" : "shipplacement-view.fxml");
        } else {
            Alert alert = new Alert(Alert.AlertType.INFORMATION);
            alert.setTitle("Partida no disponible");
            alert.setHeaderText("No se encontró una partida guardada válida");
            alert.setContentText("Crea una nueva partida o verifica que el archivo saves/game.dat exista y no esté corrupto.");
            alert.showAndWait();
            btnContinue.setDisable(true);
        }
    }

    @FXML
    private void handleExit() {
        System.exit(0);
    }
}

package com.example.battleship.controller;

import com.example.battleship.game.GameManager;
import com.example.battleship.game.GameSession;
import com.example.battleship.model.Board;
import com.example.battleship.model.Coordinate;
import com.example.battleship.model.enums.Orientation;
import com.example.battleship.model.enums.ShipType;
import com.example.battleship.model.exceptions.InvalidCoordinateException;
import com.example.battleship.model.exceptions.ShipOverLapException;
import com.example.battleship.view.SceneManager;
import com.example.battleship.view.ShipView;
import javafx.fxml.FXML;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.layout.GridPane;
import javafx.scene.layout.Pane;

import java.util.List;

public class PlacementController {

    private static final List<ShipType> COMPOSITION = com.example.battleship.model.Fleet.getStandardComposition();

    @FXML private Label lblNickname;
    @FXML private Label lblCurrentShip;
    @FXML private Label lblOrientation;
    @FXML private Label lblShipsPlaced;
    @FXML private Label lblPlacementStatus;
    @FXML private Button btnRotate;
    @FXML private Button btnRandomFill;
    @FXML private Button btnRestartPlacement;
    @FXML private Button btnStartBattle;
    @FXML private GridPane gridPlacementBoard;

    private GameManager gameManager;
    private int nextShipIndex;
    private Orientation orientation = Orientation.HORIZONTAL;

    @FXML
    public void initialize() {
        gameManager = GameSession.getInstance().requireGameManager();
        if (gameManager.getMachine().getBoard().getFleet().getShips().isEmpty()) {
            gameManager.getMachine().placeFleet();
        }

        nextShipIndex = gameManager.getHuman().getBoard().getFleet().getShips().size();
        buildGrid();
        refreshAll();
        updateStatus("Coloca tus barcos haciendo clic en el tablero.");
        btnStartBattle.setDisable(!isPlacementComplete());
    }

    private void buildGrid() {
        gridPlacementBoard.getChildren().clear();
        for (int row = 0; row < 10; row++) {
            for (int col = 0; col < 10; col++) {
                final int cellRow = row;
                final int cellCol = col;
                Pane cell = new Pane();
                cell.setPrefSize(38, 38);
                cell.setId("cell_" + cellRow + "_" + cellCol);
                cell.setStyle("-fx-border-color: rgba(56, 189, 248, 0.25); -fx-background-color: rgba(15, 23, 42, 0.75);");
                cell.setOnMouseClicked(event -> handlePlacement(cellRow, cellCol));
                gridPlacementBoard.add(cell, cellCol, cellRow);
            }
        }
    }

    private void handlePlacement(int row, int col) {
        if (isPlacementComplete()) {
            updateStatus("La flota ya está completa.");
            return;
        }

        ShipType shipType = COMPOSITION.get(nextShipIndex);
        try {
            gameManager.getHuman().getBoard().placeShip(new Coordinate(row, col), orientation, shipType);
            nextShipIndex++;
            GameSession.getInstance().saveCurrentGame();
            refreshAll();

            if (isPlacementComplete()) {
                updateStatus("Flota completa. Ya puedes iniciar la batalla.");
                btnStartBattle.setDisable(false);
            } else {
                updateStatus("Colocado " + shipType + ". Ahora coloca " + getCurrentShipLabel());
            }
        } catch (ShipOverLapException e) {
            updateStatus("No puedes superponer barcos: " + e.getMessage());
        } catch (InvalidCoordinateException | IllegalArgumentException e) {
            updateStatus("Ubicación inválida para " + shipType + ": " + e.getMessage());
        }
    }

    private void refreshAll() {
        buildGrid();
        renderShips();
        lblNickname.setText("Comandante: " + gameManager.getNickname());
        lblOrientation.setText("Orientación: " + orientation);
        lblShipsPlaced.setText("Barcos colocados: " + gameManager.getHuman().getPlacedShipsCount() + "/10");
        lblCurrentShip.setText("Siguiente barco: " + getCurrentShipLabel());
        btnStartBattle.setDisable(!isPlacementComplete());
    }

    private void renderShips() {
        Board board = gameManager.getHuman().getBoard();
        for (var ship : board.getFleet().getShips()) {
            ShipView view = ShipView.placeOnGrid(gridPlacementBoard, ship);
            view.setMouseTransparent(true);
        }
    }

    private boolean isPlacementComplete() {
        return gameManager.getHuman().isFleetComplete();
    }

    private String getCurrentShipLabel() {
        if (isPlacementComplete()) {
            return "Flota completa";
        }
        ShipType type = COMPOSITION.get(nextShipIndex);
        return type + " (" + type.getSize() + " celdas)";
    }

    private void updateStatus(String message) {
        lblPlacementStatus.setText(message);
    }

    @FXML
    private void handleRotate() {
        orientation = orientation == Orientation.HORIZONTAL ? Orientation.VERTICAL : Orientation.HORIZONTAL;
        refreshAll();
        updateStatus("Orientación cambiada a " + orientation + ".");
    }

    @FXML
    private void handleRandomFill() {
        GameSession.getInstance().startNewGame(gameManager.getNickname());
        gameManager = GameSession.getInstance().requireGameManager();
        gameManager.getHuman().placeFleet();
        nextShipIndex = COMPOSITION.size();
        refreshAll();
        updateStatus("La flota se colocó automáticamente.");
        GameSession.getInstance().saveCurrentGame();
    }

    @FXML
    private void handleRestartPlacement() {
        GameSession.getInstance().startNewGame(gameManager.getNickname());
        gameManager = GameSession.getInstance().requireGameManager();
        nextShipIndex = 0;
        orientation = Orientation.HORIZONTAL;
        refreshAll();
        updateStatus("Se reinició la colocación desde cero.");
        GameSession.getInstance().saveCurrentGame();
    }

    @FXML
    private void handleStartBattle() {
        if (!isPlacementComplete()) {
            updateStatus("Debes colocar los 10 barcos antes de iniciar.");
            return;
        }
        GameSession.getInstance().saveCurrentGame();
        SceneManager.getInstance().changeScene("game-view.fxml");
    }

    @FXML
    private void handleBackToMenu() {
        GameSession.getInstance().saveCurrentGame();
        SceneManager.getInstance().changeScene("menu-view.fxml");
    }
}

package com.example.battleship.game;

import com.example.battleship.model.players.HumanPlayer;
import com.example.battleship.model.players.MachinePlayer;
import com.example.battleship.model.enums.CellState;
import com.example.battleship.model.Coordinate;

import java.io.Serializable;

/**
 * Simple game manager that holds the two players and the turn state.
 * Serializable so it can be saved/loaded by GameSaver.
 */
public class GameManager implements Serializable {
    private static final long serialVersionUID = 1L;

    private final HumanPlayer human;
    private final MachinePlayer machine;
    private boolean humanTurn;
    private String nickname;

    public GameManager(String nickname){
        this.nickname = nickname;
        this.human = new HumanPlayer();
        this.machine = new MachinePlayer();
        this.humanTurn = true;
    }

    public HumanPlayer getHuman(){return human;}
    public MachinePlayer getMachine(){return machine;}
    public boolean isHumanTurn(){return humanTurn;}
    public void setHumanTurn(boolean t){this.humanTurn = t;}
    public String getNickname(){return nickname;}
    public void setNickname(String nickname){this.nickname = nickname;}

    /**
     * Apply a shot by the human to the machine board and return the result.
     */
    public com.example.battleship.model.enums.CellState humanShoot(Coordinate c) throws Exception{
        CellState result = machine.getBoard().shoot(c);
        // If water, switch turn
        if (result == CellState.WATER){
            humanTurn = false;
        }
        return result;
    }

    public com.example.battleship.model.enums.CellState machineShoot() throws Exception{
        Coordinate c = machine.chooseShotTarget();
        CellState result = human.getBoard().shoot(c);
        machine.registerShotResult(c, result);
        if (result == CellState.WATER){
            humanTurn = true;
        }
        return result;
    }

    public void afterLoad() {
        human.getBoard().restoreTransientState();
        machine.getBoard().restoreTransientState();
    }
}

package com.example.battleship.game;

import com.example.battleship.model.players.HumanPlayer;
import com.example.battleship.persistence.GameSaver;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public final class GameSession {
    private static final Path SAVE_FILE = Paths.get("saves", "game.dat");
    private static final Path SUMMARY_FILE = Paths.get("saves", "summary.txt");

    private static GameSession instance;
    private GameManager currentGameManager;

    private GameSession() {
    }

    public static synchronized GameSession getInstance() {
        if (instance == null) {
            instance = new GameSession();
        }
        return instance;
    }

    public GameManager getCurrentGameManager() {
        return currentGameManager;
    }

    public Path getSaveFile() {
        return SAVE_FILE;
    }

    public Path getSummaryFile() {
        return SUMMARY_FILE;
    }

    public boolean hasSavedGame() {
        return Files.exists(SAVE_FILE);
    }

    public void startNewGame(String nickname) {
        String effectiveNickname = (nickname == null || nickname.isBlank()) ? "Player1" : nickname.trim();
        currentGameManager = new GameManager(effectiveNickname);
        currentGameManager.getMachine().placeFleet();
    }

    public boolean loadLatestSave() {
        if (!hasSavedGame()) {
            currentGameManager = null;
            return false;
        }

        try {
            currentGameManager = GameSaver.load(SAVE_FILE);
            return currentGameManager != null;
        } catch (Exception e) {
            currentGameManager = null;
            System.err.println("No se pudo cargar la partida guardada: " + e.getMessage());
            return false;
        }
    }

    public void saveCurrentGame() {
        if (currentGameManager == null) {
            return;
        }

        try {
            GameSaver.save(currentGameManager, SAVE_FILE);
            GameSaver.saveSummary(currentGameManager, SUMMARY_FILE);
        } catch (IOException e) {
            System.err.println("No se pudo guardar la partida: " + e.getMessage());
        }
    }

    public HumanPlayer getHumanPlayer() {
        return currentGameManager == null ? null : currentGameManager.getHuman();
    }

    public GameManager requireGameManager() {
        if (currentGameManager == null) {
            startNewGame("Player1");
        }
        return currentGameManager;
    }
}

package com.example.battleship.model;

import com.example.battleship.model.enums.CellState;
import com.example.battleship.model.enums.Orientation;
import com.example.battleship.model.ships.Ship;
import com.example.battleship.model.enums.ShipType;
import com.example.battleship.model.exceptions.InvalidCoordinateException;
import com.example.battleship.model.exceptions.RepeatedShotException;
import com.example.battleship.model.exceptions.ShipOverLapException;
import javafx.scene.input.ScrollEvent;

import java.util.*;

import static com.example.battleship.model.enums.Orientation.HORIZONTAL;
import static com.example.battleship.model.enums.Orientation.VERTICAL;

public class Board {
    private final Map<Coordinate,Cell> board;
    private final Fleet fleet;
    public Board() {
        board=new HashMap<>();
        fleet= new Fleet();
        fillBoard();
    }

    private void fillBoard() {
        for (int row=0;row<=9;row++){
            for (int col=0; col<=9; col++){
                Coordinate coordinate= new Coordinate(row,col);
                board.put(coordinate, new Cell(coordinate));
            }
        }
    }

    public Map<Coordinate,Cell> getBoard(){
        return Collections.unmodifiableMap(board);
    }

    public void placeShip(Coordinate coordinate, Orientation orientation, ShipType shipType)throws ShipOverLapException{
        List<Coordinate> coordinatesShip=calculateShipCoordinates(coordinate, orientation, shipType);
        if (validateCells(coordinatesShip)){
            List<Cell> cells=new ArrayList<>();
            for (Coordinate coordinates: coordinatesShip){
                cells.add(getCell(coordinates));
            }
            Ship ship = ShipFactory.createShip(shipType,orientation,cells);
            fleet.addShip(ship);
            for (Cell cell: cells){
                cell.assignShip(ship);
            }
        }
    }

    private boolean validateCells(List<Coordinate>coordinatesList)throws ShipOverLapException{
        for (Coordinate coordinate: coordinatesList){
            if(getCell(coordinate).hasShip()){
                throw new ShipOverLapException("Cell is already occupied by another ship");
            }
        }
        return true;
    }

    private List<Coordinate> calculateShipCoordinates(Coordinate start, Orientation orientation, ShipType type){
        List<Coordinate> coordinates= new ArrayList<>();
        if (orientation==HORIZONTAL){
            int startRow=start.getRow();
            int endCol=start.getCol();
            for (int startCol=start.getCol(); startCol<endCol+type.getSize(); startCol++){
                coordinates.add(new Coordinate(startRow,startCol));
            }
        }
        else if (orientation==VERTICAL){
            int startCol=start.getCol();
            int endRow=start.getRow();
            for (int startRow=start.getRow(); startRow<endRow+type.getSize(); startRow++){
                coordinates.add(new Coordinate(startRow,startCol));
            }
        }else{
            throw new IllegalArgumentException("it is not vertical and horizontal");
        }
        return coordinates;
    }

    public Cell getCell(Coordinate coordinate){
        if (coordinate == null) {
            throw new IllegalArgumentException("Coordinate cannot be null");
        }
        return board.get(coordinate);
    }

    public CellState shoot(Coordinate coordinate)throws RepeatedShotException {
        return getCell(coordinate).receiveShot();
    }

    public boolean isFleetDefeated(){
        return fleet.isFleetSunk();
    }
}

package com.example.battleship.model;

import com.example.battleship.model.enums.CellState;
import com.example.battleship.model.enums.Orientation;
import com.example.battleship.model.ships.Ship;
import com.example.battleship.model.enums.ShipType;
import com.example.battleship.model.exceptions.InvalidCoordinateException;
import com.example.battleship.model.exceptions.RepeatedShotException;
import com.example.battleship.model.exceptions.ShipOverLapException;
import javafx.scene.input.ScrollEvent;

import java.io.Serializable;
import java.util.*;

import static com.example.battleship.model.enums.Orientation.HORIZONTAL;
import static com.example.battleship.model.enums.Orientation.VERTICAL;

public class Board implements Serializable {
    private static final long serialVersionUID = 1L;
    private final Map<Coordinate,Cell> board;
    private final Fleet fleet;
    private transient List<BoardListener> listeners = new ArrayList<>();
    public Board() {
        board=new HashMap<>();
        fleet= new Fleet();
        fillBoard();
    }

    private void fillBoard() {
        for (int row=0;row<=9;row++){
            for (int col=0; col<=9; col++){
                Coordinate coordinate= new Coordinate(row,col);
                board.put(coordinate, new Cell(coordinate));
            }
        }
    }

    public Map<Coordinate,Cell> getBoard(){
        return Collections.unmodifiableMap(board);
    }

    public Fleet getFleet(){
        return fleet;
    }

    public void addListener(BoardListener listener){
        if (listener==null) return;
        if (listeners==null) listeners=new ArrayList<>();
        listeners.add(listener);
    }

    public void removeListener(BoardListener listener){
        if (listeners!=null) listeners.remove(listener);
    }

    public void restoreTransientState() {
        if (listeners == null) {
            listeners = new ArrayList<>();
        }
    }

    public void placeShip(Coordinate coordinate, Orientation orientation, ShipType shipType)throws ShipOverLapException{
        List<Coordinate> coordinatesShip=calculateShipCoordinates(coordinate, orientation, shipType);
        if (validateCells(coordinatesShip)){
            List<Cell> cells=new ArrayList<>();
            for (Coordinate coordinates: coordinatesShip){
                cells.add(getCell(coordinates));
            }
            Ship ship = ShipFactory.createShip(shipType,orientation,cells);
            fleet.addShip(ship);
            for (Cell cell: cells){
                cell.assignShip(ship);
                // notify listeners about ship placement per cell
                if (listeners!=null){
                    for (BoardListener l: listeners){
                        try{ l.onCellUpdated(cell.getCoordinate(), cell.getCellState()); }catch(Exception ignore){}
                    }
                }
            }
        }
    }

    private boolean validateCells(List<Coordinate>coordinatesList)throws ShipOverLapException{
        for (Coordinate coordinate: coordinatesList){
            if(getCell(coordinate).hasShip()){
                throw new ShipOverLapException("Cell is already occupied by another ship");
            }
        }
        return true;
    }

    private List<Coordinate> calculateShipCoordinates(Coordinate start, Orientation orientation, ShipType type){
        List<Coordinate> coordinates= new ArrayList<>();
        if (orientation==HORIZONTAL){
            int startRow=start.getRow();
            int endCol=start.getCol();
            for (int startCol=start.getCol(); startCol<endCol+type.getSize(); startCol++){
                coordinates.add(new Coordinate(startRow,startCol));
            }
        }
        else if (orientation==VERTICAL){
            int startCol=start.getCol();
            int endRow=start.getRow();
            for (int startRow=start.getRow(); startRow<endRow+type.getSize(); startRow++){
                coordinates.add(new Coordinate(startRow,startCol));
            }
        }else{
            throw new IllegalArgumentException("it is not vertical and horizontal");
        }
        return coordinates;
    }

    public Cell getCell(Coordinate coordinate){
        if (coordinate == null) {
            throw new IllegalArgumentException("Coordinate cannot be null");
        }
        return board.get(coordinate);
    }

    public CellState shoot(Coordinate coordinate)throws RepeatedShotException {
        CellState result = getCell(coordinate).receiveShot();
        if (listeners!=null){
            for (BoardListener l: listeners){
                try{ l.onCellUpdated(coordinate, result);}catch(Exception ignore){}
            }
        }
        return result;
    }

    public boolean isFleetDefeated(){
        return fleet.isFleetSunk();
    }
}

package com.example.battleship.model;

import com.example.battleship.model.enums.CellState;

/**
 * Listener interface for Board changes. Implementations (UI) should register to
 * receive notifications when a cell changes state or when ships are placed.
 */
public interface BoardListener {
    void onCellUpdated(Coordinate coordinate, CellState newState);
}

package com.example.battleship.model;

import com.example.battleship.model.enums.CellState;
import com.example.battleship.model.exceptions.RepeatedShotException;
import com.example.battleship.model.ships.Ship;

public class Cell {
    private CellState cellState;
    private final Coordinate coordinate;
    private Ship ship;
    public Cell(Coordinate coordinate){
        if (coordinate==null){
            throw new IllegalArgumentException("Coordinate cannot be null");
        }
        this.coordinate=coordinate;
        cellState=CellState.EMPTY;
        ship=null;
    }
    public CellState getCellState(){return cellState;}
    public void setCellState(CellState cellState){
        if (cellState == null) {
            throw new IllegalArgumentException("State cannot be null");
        }
        this.cellState=cellState;}
    public Coordinate getCoordinate(){return coordinate;}
    public Ship getShip(){return ship;}
    public void assignShip(Ship ship){
        if (ship==null){
            throw new IllegalArgumentException("Ship cant be null");
        }
        if (hasShip()){
            throw new IllegalStateException("cell"+coordinate+" is already occupied");
        }
        this.ship=ship;
        this.cellState=CellState.OCCUPIED;
    }
    public boolean hasShip(){
        return ship!=null;
    }
    public CellState receiveShot()throws RepeatedShotException{
        if (cellState==CellState.EMPTY){
            setCellState(CellState.WATER);
            return cellState;
        }
        else if (cellState==CellState.OCCUPIED){
            setCellState(CellState.HIT);
            if(ship.registerHit()){
               return cellState;
            }
        }else{
            throw new RepeatedShotException("Cell already shot, current state: "+cellState.getSymbol(), cellState );
        }
        return cellState;
    }
    @Override
    public String toString(){
        return "Cell"+coordinate.toString()+"[State="+cellState+"]";
    }
}

