package com.example.battleship.persistence;

public class GamePersistenceException extends Exception {
    public GamePersistenceException(String message, Throwable cause) {
        super(message, cause);
    }
}

package com.example.battleship.persistence;

import com.example.battleship.game.GameManager;

import java.io.*;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.StandardOpenOption;
import java.util.List;

public class GameSaver {

    public static void save(GameManager state, Path file) throws IOException{
        Files.createDirectories(file.getParent());
        try (ObjectOutputStream out = new ObjectOutputStream(new BufferedOutputStream(Files.newOutputStream(file)))){
            out.writeObject(state);
        }
    }

    public static GameManager load(Path file) throws GamePersistenceException {
        try (ObjectInputStream in = new ObjectInputStream(new BufferedInputStream(Files.newInputStream(file)))){
            Object o = in.readObject();
            GameManager manager = (GameManager) o;
            manager.afterLoad();
            return manager;
        } catch (IOException | ClassNotFoundException | ClassCastException e) {
            throw new GamePersistenceException("No se pudo leer la partida guardada", e);
        }
    }

    /**
     * Save small plain text summary (nickname and sunk ships counts).
     */
    public static void saveSummary(GameManager state, Path file) throws IOException{
        Files.createDirectories(file.getParent());
        String line = String.format("%s,%d,%d", state.getNickname(), state.getHuman().getBoard().getFleet().getSunkShipsCount(), state.getMachine().getBoard().getFleet().getSunkShipsCount());
        Files.write(file, List.of(line), StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING);
    }
}

package com.example.battleship.view;

import com.example.battleship.model.Board;
import com.example.battleship.model.BoardListener;
import com.example.battleship.model.Coordinate;
import com.example.battleship.model.enums.CellState;
import com.example.battleship.model.ships.Ship;
import javafx.application.Platform;
import javafx.scene.Node;
import javafx.scene.layout.GridPane;
import javafx.scene.layout.Pane;

/**
 * Simple mapper that links a model Board with a GridPane created by the
 * controller. It listens to board events and updates the GridPane nodes.
 */
public class ModelToViewMapper {

    public static void bindBoardToGrid(Board board, GridPane grid, boolean showShips) {
        // place existing ships if requested
        if (showShips) {
            for (Ship ship : board.getFleet().getShips()) {
                // place ship visually using ShipView
                ShipView.placeOnGrid(grid, ship);
            }
        }

        // render all existing cell states (important for loaded games)
        for (var cellEntry : board.getBoard().entrySet()) {
            Coordinate coord = cellEntry.getKey();
            CellState state = cellEntry.getValue().getCellState();
            String id = "cell_" + coord.getRow() + "_" + coord.getCol();
            Node node = grid.lookup("#" + id);
            if (node instanceof Pane pane && (state == CellState.WATER || state == CellState.HIT || state == CellState.SUNK)) {
                pane.getChildren().clear();
                if (state == CellState.WATER) {
                    pane.getChildren().add(ShotMarkView.water());
                } else if (state == CellState.HIT) {
                    pane.getChildren().add(ShotMarkView.hit());
                } else if (state == CellState.SUNK) {
                    pane.getChildren().add(ShotMarkView.sunk());
                }
            }
        }

        // register listener to update cells when they change
        board.addListener((Coordinate coordinate, CellState newState) -> {
            Platform.runLater(() -> {
                String id = "cell_" + coordinate.getRow() + "_" + coordinate.getCol();
                Node node = grid.lookup("#" + id);
                if (node instanceof Pane pane) {
                    pane.getChildren().clear();
                    if (newState == CellState.WATER) {
                        pane.getChildren().add(ShotMarkView.water());
                    } else if (newState == CellState.HIT) {
                        pane.getChildren().add(ShotMarkView.hit());
                    } else if (newState == CellState.SUNK) {
                        pane.getChildren().add(ShotMarkView.sunk());
                    }
                }
            });
        });
    }
}

package com.example.battleship.view;

import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.stage.Stage;
import java.io.IOException;

public class SceneManager {
    private static SceneManager instance;
    private Stage stage;

    private SceneManager() {}

    public static SceneManager getInstance() {
        if (instance == null) {
            instance = new SceneManager();
        }
        return instance;
    }

    public void setStage(Stage stage) {
        this.stage = stage;
    }

    public void changeScene(String fxmlFile) {
        try {
            FXMLLoader loader = new FXMLLoader(getClass().getResource("/com/example/battleship/fxml/" + fxmlFile));
            Parent root = loader.load();
            Scene scene = new Scene(root);

            // Vincular la hoja de estilos CSS para el look oscuro/neón
            String css = getClass().getResource("/com/example/battleship/css/style.css").toExternalForm();
            scene.getStylesheets().add(css);

            stage.setScene(scene);
            stage.setTitle("Battleship - Cyber Fleet");
            stage.centerOnScreen();
            stage.show();
        } catch (IOException e) {
            System.err.println("Error crítico al intentar cargar la escena FXML: " + fxmlFile);
            e.printStackTrace();
        }
    }
}

