package com.example.battleship.view;

import com.example.battleship.model.Coordinate;
import com.example.battleship.model.enums.Orientation;
import com.example.battleship.model.ships.Ship;
import javafx.scene.Group;
import javafx.scene.layout.GridPane;
import javafx.scene.shape.Circle;
import javafx.scene.shape.Rectangle;

/**
 * Representación visual 2D de un barco, dibujada con JavaFX Shapes
 * (un Rectangle con esquinas redondeadas + dos Circle en las puntas,
 * dando una forma de "cápsula" tipo submarino/nave).
 *
 * No depende del motor de juego: solo necesita el tamaño y la
 * orientación del barco para poder dibujarse, por lo que puede
 * construirse y probarse de forma aislada, antes de que exista
 * la lógica de turnos.
 */
public class ShipView extends Group {

    /** Debe coincidir con el tamaño de celda usado en GameController (32x32). */
    public static final double CELL_SIZE = 32.0;
    private static final double MARGIN = 3.0;

    private final Rectangle body;
    private final Orientation orientation;

    public ShipView(int size, Orientation orientation) {
        this.orientation = orientation;
        this.body = buildBody(size);
        getChildren().add(body);
        addBowAndStern();
        getStyleClass().add("ship-view");
    }

    private Rectangle buildBody(int size) {
        double length = size * CELL_SIZE - MARGIN * 2;
        double thickness = CELL_SIZE - MARGIN * 2;

        Rectangle rect = new Rectangle();
        if (orientation == Orientation.HORIZONTAL) {
            rect.setWidth(length);
            rect.setHeight(thickness);
        } else {
            rect.setWidth(thickness);
            rect.setHeight(length);
        }
        rect.setX(MARGIN);
        rect.setY(MARGIN);
        rect.setArcWidth(thickness * 0.6);
        rect.setArcHeight(thickness * 0.6);
        rect.getStyleClass().add("ship-body");
        return rect;
    }

    private void addBowAndStern() {
        double radius = (CELL_SIZE - MARGIN * 2) / 2.0;

        Circle bow = new Circle(radius);
        Circle stern = new Circle(radius);
        bow.getStyleClass().add("ship-tip");
        stern.getStyleClass().add("ship-tip");

        if (orientation == Orientation.HORIZONTAL) {
            bow.setCenterX(MARGIN + radius);
            bow.setCenterY(MARGIN + radius);
            stern.setCenterX(MARGIN + body.getWidth() - radius);
            stern.setCenterY(MARGIN + radius);
        } else {
            bow.setCenterX(MARGIN + radius);
            bow.setCenterY(MARGIN + radius);
            stern.setCenterX(MARGIN + radius);
            stern.setCenterY(MARGIN + body.getHeight() - radius);
        }
        getChildren().addAll(bow, stern);
    }

    /** Aplica el estilo visual de "tocado" (aún no hundido). */
    public void markHit() {
        if (!getStyleClass().contains("ship-hit")) {
            getStyleClass().add("ship-hit");
        }
    }

    /** Aplica el estilo visual de "hundido". */
    public void markSunk() {
        getStyleClass().remove("ship-hit");
        if (!getStyleClass().contains("ship-sunk")) {
            getStyleClass().add("ship-sunk");
        }
    }

    /**
     * Construye el ShipView correspondiente a un Ship del modelo,
     * usando su tamaño y orientación.
     */
    public static ShipView from(Ship ship) {
        return new ShipView(ship.getSize(), ship.getOrientation());
    }

    /**
     * Crea el ShipView de un barco y lo agrega al GridPane, alineado
     * sobre las celdas que ocupa (usando colSpan/rowSpan según su
     * tamaño y orientación). Asume que ship.getCells() está ordenado
     * de proa a popa, tal como lo arma Board.calculateShipCoordinates().
     */
    public static ShipView placeOnGrid(GridPane grid, Ship ship) {
        ShipView view = from(ship);
        Coordinate start = ship.getCells().get(0).getCoordinate();

        int colSpan = ship.getOrientation() == Orientation.HORIZONTAL ? ship.getSize() : 1;
        int rowSpan = ship.getOrientation() == Orientation.VERTICAL ? ship.getSize() : 1;

        grid.add(view, start.getCol(), start.getRow(), colSpan, rowSpan);
        return view;
    }
}

package com.example.battleship.view;

import com.example.battleship.model.Coordinate;
import com.example.battleship.model.enums.Orientation;
import com.example.battleship.model.enums.ShipType;
import com.example.battleship.model.ships.AircraftCarrier;
import com.example.battleship.model.ships.Destroyer;
import com.example.battleship.model.ships.Frigate;
import com.example.battleship.model.ships.Ship;
import com.example.battleship.model.ships.Submarine;
import com.example.battleship.view.shapes.ShipShapeFactory;
import javafx.scene.Group;
import javafx.scene.layout.GridPane;


/**
 * Representación visual 2D de un barco, dibujada con JavaFX Shapes
 * (un Rectangle con esquinas redondeadas + dos Circle en las puntas,
 * dando una forma de "cápsula" tipo submarino/nave).
 *
 * No depende del motor de juego: solo necesita el tamaño y la
 * orientación del barco para poder dibujarse, por lo que puede
 * construirse y probarse de forma aislada, antes de que exista
 * la lógica de turnos.
 */
public class ShipView extends Group {

    /** Debe coincidir con el tamaño de celda usado en GameController (32x32). */
    public static final double CELL_SIZE = 32.0;


    private final Group shape;

    /** Construye la vista del barco usando las implementaciones detalladas en view.shapes */
    public ShipView(Ship ship) {
        ShipType type = detectType(ship);
        this.shape = ShipShapeFactory.create(type, ship.getOrientation(), CELL_SIZE);
        getChildren().add(shape);
        getStyleClass().add("ship-view");
    }

    // Los detalles de la forma están en los paquetes view.shapes; no necesitamos construir
    // manualmente rectángulos aquí. Mantenemos MARGIN por compatibilidad futura.

    /** Aplica el estilo visual de "tocado" (aún no hundido). */
    public void markHit() {
        if (!getStyleClass().contains("ship-hit")) {
            getStyleClass().add("ship-hit");
        }
    }

    /** Aplica el estilo visual de "hundido". */
    public void markSunk() {
        getStyleClass().remove("ship-hit");
        if (!getStyleClass().contains("ship-sunk")) {
            getStyleClass().add("ship-sunk");
        }
    }

    /**
      /** Construye el ShipView correspondiente a un Ship del modelo,
       * usando la forma detallada según su tipo y orientación.
       */
      public static ShipView from(Ship ship) {
          return new ShipView(ship);
      }

      private static ShipType detectType(Ship ship) {
          if (ship instanceof AircraftCarrier) return ShipType.AIRCRAFTCARRIER;
          if (ship instanceof Submarine) return ShipType.SUBMARINE;
          if (ship instanceof Destroyer) return ShipType.DESTROYER;
          if (ship instanceof Frigate) return ShipType.FRIGATE;
          // fallback by size
          switch (ship.getSize()) {
              case 4: return ShipType.AIRCRAFTCARRIER;
              case 3: return ShipType.SUBMARINE;
              case 2: return ShipType.DESTROYER;
              default: return ShipType.FRIGATE;
          }
      }

    /**
     * Crea el ShipView de un barco y lo agrega al GridPane, alineado
     * sobre las celdas que ocupa (usando colSpan/rowSpan según su
     * tamaño y orientación). Asume que ship.getCells() está ordenado
     * de proa a popa, tal como lo arma Board.calculateShipCoordinates().
     */
    public static ShipView placeOnGrid(GridPane grid, Ship ship) {
        ShipView view = from(ship);
        Coordinate start = ship.getCells().get(0).getCoordinate();

        int colSpan = ship.getOrientation() == Orientation.HORIZONTAL ? ship.getSize() : 1;
        int rowSpan = ship.getOrientation() == Orientation.VERTICAL ? ship.getSize() : 1;

        grid.add(view, start.getCol(), start.getRow(), colSpan, rowSpan);
        return view;
    }
}

package com.example.battleship.view;

import javafx.scene.Group;
import javafx.scene.shape.Circle;
import javafx.scene.shape.Line;

/**
 * Marca visual de un disparo sobre una celda individual del tablero,
 * dibujada con JavaFX Shapes. Se usa para "agua" (un punto/splash) y
 * "tocado" (una X), separado de ShipView porque estas marcas viven
 * sobre celdas sueltas, no sobre el barco completo.
 *
 * El estado "hundido" se refleja llamando a ShipView.markSunk() en el
 * barco correspondiente, no aquí.
 */
public class ShotMarkView extends Group {

    private ShotMarkView() {
        getStyleClass().add("shot-mark");
    }

    /** Punto pequeño centrado en la celda, para un disparo al agua. */
    public static ShotMarkView water() {
        ShotMarkView mark = new ShotMarkView();
        Circle splash = new Circle(ShipView.CELL_SIZE / 6.0);
        splash.setCenterX(ShipView.CELL_SIZE / 2.0);
        splash.setCenterY(ShipView.CELL_SIZE / 2.0);
        splash.getStyleClass().add("mark-water");
        mark.getChildren().add(splash);
        return mark;
    }

    /** X centrada en la celda, para un disparo que tocó un barco. */
    public static ShotMarkView hit() {
        ShotMarkView mark = new ShotMarkView();
        double margin = 8.0;
        double size = ShipView.CELL_SIZE;

        Line diagonal1 = new Line(margin, margin, size - margin, size - margin);
        Line diagonal2 = new Line(size - margin, margin, margin, size - margin);
        diagonal1.getStyleClass().add("mark-hit");
        diagonal2.getStyleClass().add("mark-hit");

        mark.getChildren().addAll(diagonal1, diagonal2);
        return mark;
    }
}

package com.example.battleship.view;

import javafx.scene.Group;
import javafx.scene.shape.Circle;
import javafx.scene.shape.Line;

/**
 * Marca visual de un disparo sobre una celda individual del tablero,
 * dibujada con JavaFX Shapes. Se usa para "agua" (un punto/splash) y
 * "tocado" (una X), separado de ShipView porque estas marcas viven
 * sobre celdas sueltas, no sobre el barco completo.
 *
 * El estado "hundido" se refleja llamando a ShipView.markSunk() en el
 * barco correspondiente, no aquí.
 */
public class ShotMarkView extends Group {

    private ShotMarkView() {
        getStyleClass().add("shot-mark");
    }

    /** Punto pequeño centrado en la celda, para un disparo al agua. */
    public static ShotMarkView water() {
        ShotMarkView mark = new ShotMarkView();
        Circle splash = new Circle(ShipView.CELL_SIZE / 6.0);
        splash.setCenterX(ShipView.CELL_SIZE / 2.0);
        splash.setCenterY(ShipView.CELL_SIZE / 2.0);
        splash.setFill(javafx.scene.paint.Color.web("#38bdf8"));
        splash.getStyleClass().add("mark-water");
        mark.getChildren().add(splash);
        return mark;
    }

    /** X centrada en la celda, para un disparo que tocó un barco. */
    public static ShotMarkView hit() {
        ShotMarkView mark = new ShotMarkView();
        double margin = 8.0;
        double size = ShipView.CELL_SIZE;

        Line diagonal1 = new Line(margin, margin, size - margin, size - margin);
        Line diagonal2 = new Line(size - margin, margin, margin, size - margin);
        diagonal1.setStroke(javafx.scene.paint.Color.web("#ef4444"));
        diagonal2.setStroke(javafx.scene.paint.Color.web("#ef4444"));
        diagonal1.setStrokeWidth(3.0);
        diagonal2.setStrokeWidth(3.0);
        diagonal1.getStyleClass().add("mark-hit");
        diagonal2.getStyleClass().add("mark-hit");

        mark.getChildren().addAll(diagonal1, diagonal2);
        return mark;
    }

    /** Marcador más intenso para una celda perteneciente a un barco hundido. */
    public static ShotMarkView sunk() {
        ShotMarkView mark = new ShotMarkView();
        Circle ring = new Circle(ShipView.CELL_SIZE / 3.8);
        ring.setCenterX(ShipView.CELL_SIZE / 2.0);
        ring.setCenterY(ShipView.CELL_SIZE / 2.0);
        ring.setFill(javafx.scene.paint.Color.rgb(239, 68, 68, 0.12));
        ring.setStroke(javafx.scene.paint.Color.web("#b91c1c"));
        ring.setStrokeWidth(2.0);
        ring.getStyleClass().add("mark-sunk");

        Line diagonal1 = new Line(7.0, 7.0, ShipView.CELL_SIZE - 7.0, ShipView.CELL_SIZE - 7.0);
        Line diagonal2 = new Line(ShipView.CELL_SIZE - 7.0, 7.0, 7.0, ShipView.CELL_SIZE - 7.0);
        diagonal1.setStroke(javafx.scene.paint.Color.web("#b91c1c"));
        diagonal2.setStroke(javafx.scene.paint.Color.web("#b91c1c"));
        diagonal1.setStrokeWidth(3.0);
        diagonal2.setStrokeWidth(3.0);
        diagonal1.getStyleClass().add("mark-sunk");
        diagonal2.getStyleClass().add("mark-sunk");

        mark.getChildren().addAll(ring, diagonal1, diagonal2);
        return mark;
    }
}

